#include <stdio.h>
#include <stdint.h>

static inline int trailing_zeros(uint64_t x){
    int cnt=0;
    while((x&1ULL)==0 && x){cnt++; x>>=1;}
    return cnt;
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        uint64_t X,Y; scanf("%llu %llu",&X,&Y);
        if(X==0 && Y==0){ printf("0\n"); continue; }
        if(X==0 || Y==0){ printf("-1\n"); continue; }
        int p=trailing_zeros(X);
        int q=trailing_zeros(Y);
        uint64_t oddX = X>>p;
        uint64_t oddY = Y>>q;
        if(oddX!=oddY){ printf("-1\n"); continue; }
        int maxExp = p>q? p:q;
        uint64_t Z = oddX << maxExp; // safe, maxExp ≤ 60 for given limits
        uint64_t ans = (uint64_t)(maxExp-p) + (uint64_t)(maxExp-q) + Z;
        printf("%llu\n", ans);
    }
    return 0;
}

