import java.io.*;
import java.util.*;

public class Main {
    private static int trailingZeros(long x){
        int cnt=0;
        while((x & 1L)==0 && x!=0){cnt++; x>>=1;}
        return cnt;
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for(int t=0;t<T;t++){
            StringTokenizer st = new StringTokenizer(br.readLine());
            long X = Long.parseUnsignedLong(st.nextToken());
            long Y = Long.parseUnsignedLong(st.nextToken());
            if(X==0 && Y==0){ out.append(0).append('\n'); continue; }
            if(X==0 || Y==0){ out.append(-1).append('\n'); continue; }
            int p = trailingZeros(X);
            int q = trailingZeros(Y);
            long oddX = X>>>p;
            long oddY = Y>>>q;
            if(oddX!=oddY){ out.append(-1).append('\n'); continue; }
            int maxExp = Math.max(p,q);
            long Z = oddX << maxExp; // safe for given limits
            long ans = (maxExp-p) + (maxExp-q) + Z;
            out.append(ans).append('\n');
        }
        System.out.print(out.toString());
    }
}

