const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let out = [];
function trailingZeros(x){
  let cnt = 0;
  while ((x & 1n) === 0n && x !== 0n){
    cnt++;
    x >>= 1n;
  }
  return cnt;
}
for(let t=0;t<T;t++){
  let X = BigInt(input[idx++]);
  let Y = BigInt(input[idx++]);
  if (X===0n && Y===0n){ out.push('0'); continue; }
  if (X===0n || Y===0n){ out.push('-1'); continue; }
  const p = trailingZeros(X);
  const q = trailingZeros(Y);
  const oddX = X >> BigInt(p);
  const oddY = Y >> BigInt(q);
  if (oddX !== oddY){ out.push('-1'); continue; }
  const maxExp = p>q? p:q;
  const Z = oddX << BigInt(maxExp);
  const ans = BigInt(maxExp - p + maxExp - q) + Z;
  out.push(ans.toString());
}
